class RateLimiter:
    def __init__(self, max_requests=30, window_seconds=60):
        self._max_requests = max_requests
        self._window = window_seconds
        self._clients = {}

    def is_allowed(self, client_id):
        now = utime.ticks_ms()
        if client_id not in self._clients:
            self._clients[client_id] = []

        timestamps = self._clients[client_id]
        cutoff = utime.ticks_add(now, -self._window * 1000)
        self._clients[client_id] = [t for t in timestamps if utime.ticks_diff(t, cutoff) > 0]

        if len(self._clients[client_id]) >= self._max_requests:
            return False

        self._clients[client_id].append(now)
        return True

    def remove_client(self, client_id):
        self._clients.pop(client_id, None)


class DeviceState:
    def __init__(self):
        self.power = False
        self.brightness = 0
        self.color = "#ffffff"
        self._led = None
        try:
            self._led = machine.Pin(2, machine.Pin.OUT)
        except Exception:
            pass

    def to_dict(self):
        return {
            "power": self.power,
            "brightness": self.brightness,
            "color": self.color
        }

    def set_power(self, on):
        self.power = bool(on)
        if self._led:
            self._led.value(1 if self.power else 0)

    def set_brightness(self, value):
        if isinstance(value, (int, float)) and 0 <= value <= 100:
            self.brightness = int(value)
        else:
            raise ValueError("Brightness must be 0-100")

    def set_color(self, color):
        if isinstance(color, str) and re.match(r'^#[0-9a-fA-F]{6}$', color):
            self.color = color
        else:
            raise ValueError("Color must be hex format #RRGGBB")


class WebSocketFrame:
    OP_TEXT = 0x1
    OP_CLOSE = 0x8
    OP_PING = 0x9
    OP_PONG = 0xA

    @staticmethod
    def decode(data):
        if len(data) < 2:
            return None, None, None

        opcode = data[0] & 0x0F
        masked = (data[1] & 0x80) != 0
        payload_len = data[1] & 0x7F

        offset = 2

        if payload_len == 126:
            if len(data) < 4:
                return None, None, None
            payload_len = int.from_bytes(data[2:4], 'big')
            offset = 4
        elif payload_len == 127:
            if len(data) < 10:
                return None, None, None
            payload_len = int.from_bytes(data[2:10], 'big')
            offset = 10

        if payload_len > MAX_MESSAGE_SIZE:
            raise ValueError("Message too large")

        if masked:
            if len(data) < offset + 4:
                return None, None, None
            mask_key = data[offset:offset + 4]
            offset += 4

        if len(data) < offset + payload_len:
            return None, None, None

        payload = bytearray(data[offset:offset + payload_len])

        if masked:
            for i in range(payload_len):
                payload[i] ^= mask_key[i % 4]

        return opcode, bytes(payload), offset + payload_len

    @staticmethod
    def encode(data, opcode=0x1):
        if isinstance(data, str):
            data = data.encode('utf-8')

        frame = bytearray()
        frame.append(0x80 | opcode)

        length = len(data)
        if length < 126:
            frame.append(length)
        elif length < 65536:
            frame.append(126)
            frame.extend(length.to_bytes(2, 'big'))
        else:
            frame.append(127)
            frame.extend(length.to_bytes(8, 'big'))

        frame.extend(data)
        return bytes(frame)


class WebSocketClient:
    def __init__(self, sock, addr):
        self.sock = sock
        self.addr = addr
        self.client_id = "{}:{}".format(addr[0], addr[1])
